import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

/**
 * Hàm cn kết hợp giữa:
 * 1. clsx: Cho phép truyền class theo kiểu object, array, conditional (true/false)
 * 2. tailwind-merge: Đảm bảo các class Tailwind sau cùng sẽ ghi đè các class trước đó một cách chính xác
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;500;600;700&family=Inter:wght@400;500;600;700&display=swap');
@import "tailwindcss";
@plugin "tailwindcss-animate";
@custom-variant dark (&:where(.dark, .dark *));
/* Thin scrollbar — auto-hide */
* {
    scrollbar-width: thin;
    scrollbar-color: transparent transparent;
}

*:hover {
    scrollbar-color: var(--border) transparent;
}

*::-webkit-scrollbar {
    width: 4px;
    height: 4px;
}

*::-webkit-scrollbar-track {
    background: transparent;
}

*::-webkit-scrollbar-thumb {
    background: transparent;
    border-radius: 9999px;
}

*:hover::-webkit-scrollbar-thumb {
    background: var(--border);
}

*::-webkit-scrollbar-thumb:hover {
    background: var(--muted-foreground);
}

/*
  View Transitions API: Tắt animation mặc định (fade cross-dissolve).
  ThemeToggle sẽ tự định nghĩa clip-path ripple animation thay thế.
*/
::view-transition-old(root),
::view-transition-new(root) {
    animation: none;
    mix-blend-mode: normal;
}

::view-transition-old(root) {
    z-index: 1;
}

::view-transition-new(root) {
    z-index: 9999;
}


@theme {
  --animate-ping: ping 1.5s linear infinite; /* Chỉnh cho nó chạy chậm lại */



    --color-background: var(--background);
    --color-foreground: var(--foreground);

    --color-primary: var(--primary);
    --color-primary-foreground: var(--primary-foreground);

    --color-secondary: var(--secondary);
    --color-secondary-foreground: var(--secondary-foreground);

    --color-muted: var(--muted);
    --color-muted-foreground: var(--muted-foreground);

    --color-accent: var(--accent);
    --color-accent-foreground: var(--accent-foreground);

    --color-switch-background: var(--switch-background);

    --color-border: var(--border);

    --color-success: var(--success);
    --color-success-foreground: var(--success-foreground);

    --color-warning: var(--warning);
    --color-warning-foreground: var(--warning-foreground);

    --color-destructive: var(--danger);
    --color-destructive-foreground: var(--danger-foreground);

    --color-danger: var(--danger);
    --color-danger-foreground: var(--danger-foreground);

    --color-ring: var(--ring);
    --color-input: var(--input);

    --color-chart-1: var(--chart-1);
    --color-chart-2: var(--chart-2);
    --color-chart-3: var(--chart-3);
    --color-chart-4: var(--chart-4);
    --color-chart-5: var(--chart-5);

    --color-popover: var(--popover);
    --color-popover-foreground: var(--popover-foreground);

    --color-sidebar: var(--sidebar);
    --color-sidebar-foreground: var(--sidebar-foreground);
    --color-sidebar-border: var(--sidebar-border);
    --color-sidebar-accent: var(--sidebar-accent);
    --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
    --color-sidebar-ring: var(--sidebar-ring);

    /* ─── Kraken-inspired radius scale ───────────────────────────────────────── */
    --radius-sm: 0.375rem;   /* 6px  — badges, tags */
    --radius-md: 0.5rem;     /* 8px  — tooltips, popovers */
    --radius-lg: 0.75rem;    /* 12px — buttons, inputs, cards */
    --radius-xl: 1rem;       /* 16px — modals, large containers */

    /* ─── Shadow tokens ───────────────────────────────────────────────────────── */
    --shadow-subtle: rgba(0,0,0,0.03) 0px 4px 24px;
    --shadow-micro:  rgba(16,24,40,0.04) 0px 1px 4px;

    /* ─── Font families ───────────────────────────────────────────────────────── */
    --font-display: 'IBM Plex Sans', Helvetica, Arial, sans-serif;
    --font-ui:      'Inter', 'Helvetica Neue', Helvetica, Arial, sans-serif;

    /* Z-index scale */
    --z-dropdown: 50;
    --z-sticky: 100;
    --z-overlay: 200;
    --z-modal: 300;
    --z-popover: 400;
    --z-toast: 500;

    --animate-spin-slow: spin 3s linear infinite;
    --animate-progress-stripes: progress-stripes 1s linear infinite;

    @keyframes progress-stripes {
        from { background-position: 1rem 0; }
        to { background-position: 0 0; }
    }

    --animate-blink: blink 1s step-end infinite;
    @keyframes blink {
        0%, 100% { opacity: 1; }
        50% { opacity: 0; }
    }
}

@layer base {
    :root {
        /* GENERATED:theme-start */
        /* Auto-generated from themes.ts — run `npm run theme:sync` to update */
        --background: #ffffff;
        --foreground: #101114;              /* Kraken Near Black */
        --primary: #7132f5;                 /* Kraken Purple */
        --primary-foreground: #ffffff;
        --secondary: #ebe5fe;               /* Purple Subtle — rgba(133,91,251,0.16) on white */
        --secondary-foreground: #5741d8;    /* Purple Dark */
        --muted: #f8f8fb;                   /* Cool off-white */
        --muted-foreground: #9497a9;        /* Kraken Silver Blue */
        --accent: #f5f4ff;                  /* Light purple tint */
        --accent-foreground: #101114;
        --success: #149e61;                 /* Kraken Green */
        --success-foreground: #ffffff;
        --warning: #f59e0b;
        --warning-foreground: #ffffff;
        --danger: #ef4444;
        --danger-foreground: #ffffff;
        --destructive: #ef4444;
        --destructive-foreground: #ffffff;
        --border: #dedee5;                  /* Kraken Border Gray */
        --input: #dedee5;
        --ring: #7132f5;
        --popover: #ffffff;
        --popover-foreground: #101114;
        /* GENERATED:theme-end */

        /* Non-theme tokens (not managed by applyTheme) */
        --switch-background: #c0c2d1;       /* Cool gray toggle */

        --chart-1: #e11d48;
        --chart-2: #7132f5;                 /* Kraken Purple */
        --chart-3: #149e61;                 /* Kraken Green */
        --chart-4: #f59e0b;
        --chart-5: #5741d8;                 /* Purple Dark */

        --sidebar: #f8f8fb;
        --sidebar-foreground: #101114;
        --sidebar-border: #dedee5;
        --sidebar-accent: #f5f4ff;
        --sidebar-accent-foreground: #7132f5;
        --sidebar-ring: #7132f5;
    }

    .dark {
        /* Dark Theme — Kraken-inspired Deep Purple Night */
        --background: #0e0c14;              /* Near-black with purple tint */
        --foreground: #ededf0;              /* Off-white */

        --primary: #9b72ff;                 /* Lighter Kraken Purple — readable on dark */
        --primary-foreground: #ffffff;

        --secondary: #1c1929;               /* Dark purple-tinted surface */
        --secondary-foreground: #c4b0ff;    /* Soft lavender */

        --muted: #17151f;                   /* Deeper surface */
        --muted-foreground: #7b7d99;        /* Muted silver-blue */

        --accent: #1c1929;
        --accent-foreground: #ededf0;

        --switch-background: #3d3860;

        --border: #2a2740;                  /* Dark purple-tinted border */
        --input: #2a2740;

        --success: #1acc72;                 /* Brighter Kraken green for dark bg */
        --success-foreground: #ffffff;

        --warning: #f59e0b;
        --warning-foreground: #ffffff;

        --danger: #f05555;
        --danger-foreground: #ffffff;

        --ring: #9b72ff;

        --chart-1: #fb7185;
        --chart-2: #9b72ff;
        --chart-3: #1acc72;
        --chart-4: #fbbf24;
        --chart-5: #c4b0ff;

        --popover: #17151f;
        --popover-foreground: #ededf0;

        --sidebar: #0b0a11;
        --sidebar-foreground: #ededf0;
        --sidebar-border: #2a2740;
        --sidebar-accent: #1c1929;
        --sidebar-accent-foreground: #c4b0ff;
        --sidebar-ring: #9b72ff;
    }
}


@layer base {
    * {
        border-color: var(--border);
    }

    html, body {
        margin: 0;
        padding: 0;
        background-color: var(--background);
        color: var(--foreground);
        font-family: var(--font-ui);
        overflow: hidden; /* Khóa scroll tổng để dùng nội bộ */
        height: 100%;
        color-scheme: light;
        transition: background-color 0.3s ease, color 0.3s ease;
    }

    html.dark {
        color-scheme: dark;
    }

    /* Fix dải trắng khi mở modal/dialog trong các thư viện (Base UI, Radix) */
    body[style*="overflow: hidden"],
    body[data-scroll-locked] {
        padding-right: 0 !important;
        margin-right: 0 !important;
    }

    /* Đảm bảo Backdrop luôn phủ kín màn hình bất chấp các tính toán của thư viện */
    [data-base-ui-dialog-backdrop],
    .base-ui-backdrop,
    [role="presentation"] > div[style*="fixed"] {
        width: 100vw !important;
        height: 100vh !important;
        left: 0 !important;
        top: 0 !important;
        right: 0 !important;
        bottom: 0 !important;
    }

    /* Custom Scrollbar - Sleek & Modern */
    ::-webkit-scrollbar {
        width: 8px;
        height: 8px;
    }

    ::-webkit-scrollbar-track {
        background: transparent;
    }

    ::-webkit-scrollbar-thumb {
        background: #c0c2d1; /* Kraken cool gray */
        border-radius: 10px;
        border: 2px solid transparent;
        background-clip: content-box;
    }

    .dark ::-webkit-scrollbar-thumb {
        background: #2a2740;
    }

    ::-webkit-scrollbar-thumb:hover {
        background: #9497a9; /* Kraken Silver Blue */
        background-clip: content-box;
    }

    .dark ::-webkit-scrollbar-thumb:hover {
        background: #3d3860;
    }

    /* Firefox */
    * {
        scrollbar-width: thin;
        scrollbar-color: #c0c2d1 transparent;
    }

    .dark * {
        scrollbar-color: #2a2740 transparent;
    }
}

/* ─── Reduced Motion ─────────────────────────────────────────────────────────
   Respect prefers-reduced-motion for a11y.
   Disables all animations and transitions globally when the user's OS
   requests reduced motion. Individual components can opt-out via
   motion-reduce:* utilities if an animation is essential.
*/
@media (prefers-reduced-motion: reduce) {
    *, *::before, *::after {
        animation-duration: 0.01ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0.01ms !important;
        scroll-behavior: auto !important;
    }
}

/* Ensure data-state="checked" always works for background */
[data-state="checked"] {
    &.bg-primary {
        background-color: var(--primary);
    }
}

[data-state="indeterminate"] {
    &.bg-primary {
        background-color: var(--primary);
    }
}

// ─── Token Interfaces ─────────────────────────────────────────────────────────

