// ─── Apply Theme ──────────────────────────────────────────────────────────────

const THEME_STYLE_ID = 'basuicn-theme';

/**
 * Applies a theme by injecting a <style> tag at the START of <head>.
 *
 * Why <style> tag instead of element.style.setProperty():
 *   Inline styles have the highest CSS specificity and would override
 *   .dark { } class rules, breaking dark mode. A <style> tag injected
 *   before the app's CSS bundle has lower specificity than .dark { }
 *   rules defined later in the bundle — so dark mode always wins.
 */
export function applyTheme(theme: Theme) {
  if (typeof window === 'undefined') return;
  if (!theme?.colors) return;
  const { colors: c } = theme;

  const css = `
:root:not(.dark) {
  --background: ${c.background};
  --foreground: ${c.foreground};
  --primary: ${c.primary};
  --primary-foreground: ${c.primaryForeground};
  --secondary: ${c.secondary};
  --secondary-foreground: ${c.secondaryForeground};
  --muted: ${c.muted};
  --muted-foreground: ${c.mutedForeground};
  --accent: ${c.accent};
  --accent-foreground: ${c.accentForeground};
  --success: ${c.success};
  --success-foreground: ${c.successForeground};
  --warning: ${c.warning};
  --warning-foreground: ${c.warningForeground};
  --danger: ${c.danger};
  --danger-foreground: ${c.dangerForeground};
  --destructive: ${c.danger};
  --destructive-foreground: ${c.dangerForeground};
  --border: ${c.border};
  --input: ${c.input};
  --ring: ${c.ring};
  --popover: ${c.popover};
  --popover-foreground: ${c.popoverForeground};
}`.trim();

  let styleEl = document.getElementById(THEME_STYLE_ID) as HTMLStyleElement | null;
  if (!styleEl) {
    styleEl = document.createElement('style');
    styleEl.id = THEME_STYLE_ID;
    document.head.appendChild(styleEl);
  }
  styleEl.textContent = css;
}

// ─── CSS Variable Generator ───────────────────────────────────────────────────

/**
 * Converts a Theme's colors into a CSS `:root { }` block string.
 * Used by scripts to generate or sync CSS.
 */
export function toCssVars(theme: Theme): string {
  const { colors: c } = theme;
  const vars: [string, string][] = [
    ['--background', c.background],
    ['--foreground', c.foreground],
    ['--primary', c.primary],
    ['--primary-foreground', c.primaryForeground],
    ['--secondary', c.secondary],
    ['--secondary-foreground', c.secondaryForeground],
    ['--muted', c.muted],
    ['--muted-foreground', c.mutedForeground],
    ['--accent', c.accent],
    ['--accent-foreground', c.accentForeground],
    ['--success', c.success],
    ['--success-foreground', c.successForeground],
    ['--warning', c.warning],
    ['--warning-foreground', c.warningForeground],
    ['--danger', c.danger],
    ['--danger-foreground', c.dangerForeground],
    ['--destructive', c.danger],
    ['--destructive-foreground', c.dangerForeground],
    ['--border', c.border],
    ['--input', c.input],
    ['--ring', c.ring],
    ['--popover', c.popover],
    ['--popover-foreground', c.popoverForeground],
  ];
  const body = vars.map(([k, v]) => `        ${k}: ${v};`).join('\n');
  return `:root {\n${body}\n    }`;
}

// ─── Custom Theme Factory ─────────────────────────────────────────────────────

/**
 * Creates a custom theme by merging overrides with the default (indigo) theme.
 *
 * @example
 * const myTheme = createTheme('brand', 'My Brand', { primary: '#ff6b35' });
 */
export function createTheme(
  name: string,
  label: string,
  colors: Partial<ThemeColors>
): Theme {
  const base = themes[0]; // indigo as default base
  return {
    name,
    label,
    colors: { ...base.colors, ...colors },
  };
}

'use client';

import { createContext, useContext, useState, useEffect, type ReactNode } from 'react';
import { themes, applyTheme, createTheme, type Theme, type ThemeColors, type BuiltInThemeName } from './themes';

const STORAGE_KEY = 'ui-theme';

/**
 * Union type for autocomplete suggestions while allowing any string.
 */
export type ThemeName = BuiltInThemeName | (string & {});

interface ThemeContextValue {
  currentTheme: Theme;
  setTheme: (name: ThemeName) => void;
  /** Register and switch to a custom theme */
  setCustomTheme: (name: string, label: string, colors: Partial<ThemeColors>) => void;
  themes: Theme[];
}

const ThemeContext = createContext<ThemeContextValue>({
  currentTheme: themes[0],
  setTheme: () => {},
  setCustomTheme: () => {},
  themes,
});

interface ThemeProviderProps {
  children: ReactNode;
  defaultTheme?: ThemeName;
}

const getStoredTheme = (allThemes: Theme[], defaultThemeName?: ThemeName): Theme => {
  if (typeof window === 'undefined') return allThemes[0];
  // defaultTheme prop in code takes priority over localStorage
  if (defaultThemeName) {
    return allThemes.find(t => t.name === defaultThemeName) ?? allThemes[0];
  }
  try {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      return allThemes.find(t => t.name === saved) ?? allThemes[0];
    }
    return allThemes[0];
  } catch {
    return allThemes[0];
  }
};

export function ThemeProvider({ children, defaultTheme }: ThemeProviderProps) {
  const [allThemes, setAllThemes] = useState<Theme[]>(themes);
  const [currentTheme, setCurrentTheme] = useState<Theme>(() => getStoredTheme(themes, defaultTheme));

  useEffect(() => {
    applyTheme(currentTheme);
  }, [currentTheme]);

  const setTheme = (name: ThemeName) => {
    const found = allThemes.find(t => t.name === name);
    if (!found) return;
    try { localStorage.setItem(STORAGE_KEY, name); } catch { /* SSR / quota */ }
    setCurrentTheme(found);
  };

  const setCustomTheme = (name: string, label: string, colors: Partial<ThemeColors>) => {
    const custom = createTheme(name, label, colors);
    setAllThemes(prev => {
      const exists = prev.findIndex(t => t.name === name);
      return exists >= 0
        ? prev.map(t => t.name === name ? custom : t)
        : [...prev, custom];
    });
    try { localStorage.setItem(STORAGE_KEY, name); } catch { /* SSR / quota */ }
    setCurrentTheme(custom);
  };

  return (
    <ThemeContext.Provider value={{ currentTheme, setTheme, setCustomTheme, themes: allThemes }}>
      {children}
    </ThemeContext.Provider>
  );
}

export const useTheme = () => useContext(ThemeContext);

