    empty: 'py-8 text-center text-sm text-muted-foreground',
    shortcut: 'ml-auto text-xs tracking-widest text-muted-foreground/70',
  },
});

const styles = commandVariants();

// ─── Context ─────────────────────────────────────────────────────────────────

interface CommandContextValue {
  search: string;
  setSearch: React.Dispatch<React.SetStateAction<string>>;
  highlightedIndex: number;
  setHighlightedIndex: React.Dispatch<React.SetStateAction<number>>;
  visibleItemCount: number;
  setVisibleItemCount: React.Dispatch<React.SetStateAction<number>>;
}

const CommandContext = React.createContext<CommandContextValue | null>(null);

function useCommand() {
  const ctx = React.useContext(CommandContext);
  if (!ctx) throw new Error('useCommand must be used within <Command>');
  return ctx;
}

interface GroupContextValue {
  groupId: string;
  visibleCount: number;
  setVisibleCount: React.Dispatch<React.SetStateAction<number>>;
}

const GroupContext = React.createContext<GroupContextValue | null>(null);

function useGroup() {
  return React.useContext(GroupContext);
}

// ─── Command (Root) ──────────────────────────────────────────────────────────

export interface CommandProps {
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
  children: React.ReactNode;
  className?: string;
}

const Command: React.FC<CommandProps> = ({ open, onOpenChange, children, className }) => {
  const [search, setSearch] = React.useState('');
  const [highlightedIndex, setHighlightedIndex] = React.useState(0);
  const [visibleItemCount, setVisibleItemCount] = React.useState(0);

  React.useEffect(() => {
    if (open) {
      setSearch('');
      setHighlightedIndex(0);
      setVisibleItemCount(0);
    }
  }, [open]);

  return (
    <CommandContext.Provider value={{ search, setSearch, highlightedIndex, setHighlightedIndex, visibleItemCount, setVisibleItemCount }}>
      <BaseDialog.Root open={open} onOpenChange={onOpenChange}>
        <BaseDialog.Portal>
          <BaseDialog.Backdrop className={styles.overlay()} />
          <BaseDialog.Popup className={cn(styles.content(), className)}>
            {children}
          </BaseDialog.Popup>
        </BaseDialog.Portal>
      </BaseDialog.Root>
    </CommandContext.Provider>
  );
};
Command.displayName = 'Command';

// ─── CommandInput ────────────────────────────────────────────────────────────

export interface CommandInputProps extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'onChange'> {
  onValueChange?: (value: string) => void;
}

const CommandInput = React.forwardRef<HTMLInputElement, CommandInputProps>(
  ({ className, placeholder = 'Type a command or search...', onValueChange, ...props }, ref) => {
    const { search, setSearch, setHighlightedIndex } = useCommand();

    return (
      <div className="flex items-center border-b border-border px-3 shrink-0">
        <Search className="mr-2 h-4 w-4 shrink-0 text-muted-foreground" />
        <input
          ref={ref}
          value={search}
          onChange={(e) => {
            setSearch(e.target.value);
            setHighlightedIndex(0);
            onValueChange?.(e.target.value);
          }}
          placeholder={placeholder}
          className={cn(styles.input(), className)}
          {...props}
        />
      </div>
    );
  },
);
CommandInput.displayName = 'CommandInput';

// ─── CommandList ─────────────────────────────────────────────────────────────

const CommandList = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, children, ...props }, ref) => (
    <div ref={ref} className={cn(styles.list(), className)} role="listbox" {...props}>
      {children}
    </div>
  ),
);
CommandList.displayName = 'CommandList';

// ─── CommandGroup ────────────────────────────────────────────────────────────

export interface CommandGroupProps extends React.HTMLAttributes<HTMLDivElement> {
  heading?: string;
}

const CommandGroup = React.forwardRef<HTMLDivElement, CommandGroupProps>(
  ({ className, heading, children, ...props }, ref) => {
    const [groupId] = React.useState(() => Math.random().toString(36));
    const [visibleCount, setVisibleCount] = React.useState(0);

    return (
      <GroupContext.Provider value={{ groupId, visibleCount, setVisibleCount }}>
        <div ref={ref} className={cn(styles.group(), className)} role="group" {...props}>
          {heading && visibleCount > 0 && <div className={styles.groupLabel()}>{heading}</div>}
          {children}
        </div>
      </GroupContext.Provider>
    );
  }
);
CommandGroup.displayName = 'CommandGroup';

// ─── CommandItem ─────────────────────────────────────────────────────────────

export interface CommandItemProps extends React.HTMLAttributes<HTMLDivElement> {
  disabled?: boolean;
  keywords?: string[];
  onSelect?: () => void;
  value?: string;
}

const CommandItem = React.forwardRef<HTMLDivElement, CommandItemProps>(
  ({ className, disabled, keywords = [], onSelect, value, children, ...props }, ref) => {
    const { search, highlightedIndex, setHighlightedIndex, setVisibleItemCount } = useCommand();
    const [itemIndex] = React.useState(() => Math.random());

    // Filter: check value, text content, and keywords
    const searchable = [value ?? '', ...(typeof children === 'string' ? [children] : []), ...keywords]
      .join(' ')
      .toLowerCase();
    const isVisible = !search || searchable.includes(search.toLowerCase());

    const group = useGroup();

    React.useEffect(() => {
      setVisibleItemCount((prev) => prev + (isVisible ? 1 : 0));
      group?.setVisibleCount((prev) => prev + (isVisible ? 1 : 0));
      return () => {
        setVisibleItemCount((prev) => prev - (isVisible ? 1 : 0));
        group?.setVisibleCount((prev) => prev - (isVisible ? 1 : 0));
      };
    }, [isVisible, setVisibleItemCount, group]);

    if (!isVisible) return null;

    return (
      <div
        ref={ref}
        role="option"
        aria-disabled={disabled || undefined}
        className={cn(
          styles.item(),
          disabled && 'opacity-50 pointer-events-none',
          className,
        )}
        onClick={() => {
          if (!disabled) onSelect?.();
        }}
        onKeyDown={(e) => {
          if ((e.key === 'Enter' || e.key === ' ') && !disabled) {
            e.preventDefault();
            onSelect?.();
          }
        }}
        {...props}
      >
        {children}
      </div>
    );
  },
);
CommandItem.displayName = 'CommandItem';

// ─── CommandEmpty ────────────────────────────────────────────────────────────

const CommandEmpty = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, children = 'No results found.', ...props }, ref) => {
    const { visibleItemCount } = useCommand();
    if (visibleItemCount > 0) return null;
    return (
      <div ref={ref} className={cn(styles.empty(), className)} {...props}>
        {children}
      </div>
    );
  },
);
CommandEmpty.displayName = 'CommandEmpty';

// ─── CommandSeparator ────────────────────────────────────────────────────────

const CommandSeparator = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn(styles.separator(), className)} {...props} />
  ),
);
CommandSeparator.displayName = 'CommandSeparator';

// ─── CommandShortcut ─────────────────────────────────────────────────────────

const CommandShortcut = ({ className, ...props }: React.HTMLAttributes<HTMLSpanElement>) => (
  <span className={cn(styles.shortcut(), className)} {...props} />
);
CommandShortcut.displayName = 'CommandShortcut';

// ─── Exports ─────────────────────────────────────────────────────────────────

export {
  Command,
  CommandInput,
  CommandList,
  CommandGroup,
  CommandItem,
  CommandEmpty,
  CommandSeparator,
  CommandShortcut,
};

