// ─── Variants ────────────────────────────────────────────────────────────────

const inputOTPVariants = tv({
  slots: {
    root: 'flex items-center gap-2',
    slot: [
      'relative flex items-center justify-center',
      'border border-border bg-background text-foreground font-semibold',
