          <p id={`${rootId}-desc`} className="text-[0.8rem] text-muted-foreground">{description}</p>
        )}
        {(error || errorMessage) && (
          <p id={`${rootId}-err`} className="text-[0.8rem] font-medium text-danger">{errorMessage || 'Invalid code'}</p>
        )}
      </div>
    );
  },
);

