export { Popover, PopoverTrigger, PopoverContent, PopoverClose };

import React, { useState, useEffect, useCallback } from 'react';
import { createHighlighter, type Highlighter } from 'shiki';
import { unified } from 'unified';
import rehypeParse from 'rehype-parse';
import rehypeReact from 'rehype-react';
import * as prod from 'react/jsx-runtime';
import { Copy, Check } from 'lucide-react';
import { cn } from '@/lib/utils/cn';

// ─── Singleton highlighter ────────────────────────────────────────────────────
let globalHighlighter: Highlighter | null = null;

const getHighlighter = async () => {
    if (globalHighlighter) return globalHighlighter;
    globalHighlighter = await createHighlighter({
        themes: ['nord'],
        langs: ['tsx', 'typescript', 'javascript', 'bash', 'json'],
    });
    return globalHighlighter;
};

// ─── Helpers ──────────────────────────────────────────────────────────────────
const LANG_LABELS: Record<string, string> = {
    tsx: 'TSX',
    typescript: 'TypeScript',
    javascript: 'JavaScript',
    bash: 'Bash',
    json: 'JSON',
};

// Fixed widths for loading skeleton rows
const SKELETON_WIDTHS = ['68%', '82%', '54%', '76%', '45%', '60%'];

// ─── Types ────────────────────────────────────────────────────────────────────
interface PrettyCodeProps {
    code: string;
    lang?: string;
    /** Optional filename shown in the header bar */
    filename?: string;
    className?: string;
}

// ─── Component ────────────────────────────────────────────────────────────────
export const PrettyCode: React.FC<PrettyCodeProps> = ({
    code,
    lang = 'tsx',
    filename,
    className,
}) => {
    const [nodes, setNodes] = useState<React.ReactNode>(null);
    const [loading, setLoading] = useState(true);
    const [copied, setCopied] = useState(false);

    useEffect(() => {
        let isMounted = true;
        setLoading(true);
        setNodes(null);

        const highlight = async () => {
            try {
                const highlighter = await getHighlighter();
                const html = highlighter.codeToHtml(code, { lang, theme: 'nord' });

                const file = await unified()
                    .use(rehypeParse, { fragment: true })
                    .use(rehypeReact, { ...prod })
                    .process(html);

                if (isMounted) {
                    setNodes(file.result as React.ReactNode);
                    setLoading(false);
                }
            } catch (err) {
                console.error('Failed to highlight code:', err);
                if (isMounted) setLoading(false);
            }
        };

        highlight();
        return () => { isMounted = false; };
    }, [code, lang]);

    const handleCopy = useCallback(async () => {
        try {
            await navigator.clipboard.writeText(code);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        } catch {
            // clipboard not available
        }
    }, [code]);

    const langLabel = LANG_LABELS[lang] ?? lang.toUpperCase();

    return (
        <div className={cn('rounded-xl overflow-hidden border border-white/[0.07] bg-[#2e3440] shadow-2xl', className)}>

            {/* ── Header bar ── */}
            <div className="flex items-center justify-between px-4 py-2.5 bg-[#252b37] border-b border-white/[0.07] select-none">

                {/* Left: window dots + filename */}
                <div className="flex items-center gap-3 min-w-0">
                    <div className="flex items-center gap-1.5 shrink-0">
                        <span className="w-3 h-3 rounded-full bg-[#ff5f57]" />
                        <span className="w-3 h-3 rounded-full bg-[#febc2e]" />
                        <span className="w-3 h-3 rounded-full bg-[#28c840]" />
                    </div>
                    {filename && (
                        <span className="text-[11px] text-zinc-400 font-mono truncate leading-none">
                            {filename}
                        </span>
                    )}
                </div>

                {/* Right: language badge + copy button */}
                <div className="flex items-center gap-2 shrink-0 ml-4">
                    <span className="hidden sm:block text-[10px] font-bold tracking-widest text-zinc-600 uppercase">
                        {langLabel}
                    </span>

                    <button
                        onClick={handleCopy}
                        aria-label="Copy code"
                        className={cn(
                            'flex items-center gap-1.5 px-2 py-1 rounded-md',
                            'text-xs font-medium transition-all duration-150 active:scale-95',
                            copied
                                ? 'text-emerald-400 bg-emerald-400/10'
                                : 'text-zinc-400 hover:text-zinc-100 hover:bg-white/10',
                        )}
                    >
                        {copied
                            ? <Check className="w-3.5 h-3.5 shrink-0" />
                            : <Copy className="w-3.5 h-3.5 shrink-0" />
                        }
                        <span className="hidden sm:inline w-[42px]">
                            {copied ? 'Copied!' : 'Copy'}
                        </span>
                    </button>
                </div>
            </div>

            {/* ── Code area ── */}
            {loading ? (
                <div className="p-5 space-y-3 animate-pulse" aria-hidden>
                    {SKELETON_WIDTHS.map((w, i) => (
                        <div
                            key={i}
                            className="h-3.5 rounded-full bg-white/[0.08]"
                            style={{ width: w }}
                        />
                    ))}
                </div>
            ) : (
                <div
                    className="overflow-x-auto
                        [&_pre]:!bg-transparent [&_pre]:m-0
                        [&_pre]:px-5 [&_pre]:py-4
                        [&_pre]:text-[13px] [&_pre]:leading-[1.7]
                        [&_code]:font-mono [&_code]:text-[13px]"
                >
                    {nodes}
                </div>
            )}
        </div>
    );
};

import * as React from 'react';
import { Popover as BasePopover } from '@base-ui/react';
import { tv, type VariantProps } from 'tailwind-variants';
import { Button } from '../button/Button';

const previewCardVariants = tv({
  slots: {
    popup: [
      'z-50 w-72 rounded-xl border border-border bg-background shadow-xl outline-none',
      'data-starting:animate-in data-ending:animate-out',
      'data-ending:fade-out-0 data-starting:fade-in-0',
      'data-ending:zoom-out-95 data-starting:zoom-in-95',
      'data-side-bottom:slide-in-from-top-2',
      'data-side-left:slide-in-from-right-2',
      'data-side-right:slide-in-from-left-2',
      'data-side-top:slide-in-from-bottom-2',
    ],
    cover: 'w-full overflow-hidden rounded-t-xl',
    body: 'p-4 space-y-2',
    title: 'font-semibold text-sm text-foreground leading-tight',
    description: 'text-xs text-muted-foreground leading-relaxed',
    footer: 'px-4 pb-4 pt-0 border-t border-border/50 mt-2 pt-3',
  },
});

export type PreviewCardSide = 'top' | 'right' | 'bottom' | 'left';
export type PreviewCardAlign = 'start' | 'center' | 'end';

/** Props for the PreviewCard component */
export interface PreviewCardProps {
  /** Element that triggers the preview card */
  trigger: React.ReactNode;
  /** Title text displayed in the card body */
  title?: string;
  /** Description text displayed below the title */
  description?: string;
  /** URL for the cover image at the top of the card */
  coverImage?: string;
  /** Alt text for the cover image */
  coverAlt?: string;
  /** Height in px of the cover image area */
  coverHeight?: number;
  children?: React.ReactNode;
  /** Content rendered in the card footer section */
  footerContent?: React.ReactNode;
  /** Which side of the trigger to render the card */
  side?: PreviewCardSide;
  /** Alignment relative to the trigger */
  align?: PreviewCardAlign;
  /** Distance in px between the trigger and the card */
  sideOffset?: number;
  /** Open the card on hover instead of click */
  openOnHover?: boolean;
  /** Width of the card in px */
  width?: number;
  className?: string;
}

const PreviewCard = React.forwardRef<HTMLSpanElement, PreviewCardProps>(({
  trigger,
  title,
  description,
  coverImage,
  coverAlt = '',
  coverHeight = 120,
  children,
  footerContent,
  side = 'bottom',
  align = 'start',
  sideOffset = 8,
  openOnHover = false,
  width = 288,
  className,
}, ref) => {
  const [open, setOpen] = React.useState(false);
  const slots = previewCardVariants();

  const triggerProps = openOnHover
    ? {
        onMouseEnter: () => setOpen(true),
        onMouseLeave: () => setOpen(false),
      }
    : {};

  return (
    <BasePopover.Root open={open} onOpenChange={setOpen}>
      <BasePopover.Trigger
        nativeButton={false}
        render={
          <span
            ref={ref}
            className="inline-block cursor-pointer"
            {...triggerProps}
          >
            {trigger}
          </span>
        }
      />
      <BasePopover.Portal>
        <BasePopover.Positioner side={side} align={align} sideOffset={sideOffset}>
          <BasePopover.Popup
            className={slots.popup({ className })}
            style={{ width }}
          >
            {coverImage && (
              <div className={slots.cover()} style={{ height: coverHeight }}>
                <img
                  src={coverImage}
                  alt={coverAlt}
                  className="w-full h-full object-cover"
                />
              </div>
            )}
            {(title || description || children) && (
              <div className={slots.body()}>
                {title && <p className={slots.title()}>{title}</p>}
                {description && <p className={slots.description()}>{description}</p>}
                {children}
              </div>
            )}
            {footerContent && (
              <div className={slots.footer()}>{footerContent}</div>
            )}
          </BasePopover.Popup>
        </BasePopover.Positioner>
      </BasePopover.Portal>
    </BasePopover.Root>
  );
});

PreviewCard.displayName = 'PreviewCard';

export { PreviewCard };

import * as React from 'react';
import { Progress as BaseProgress } from '@base-ui/react';
import { tv, type VariantProps } from 'tailwind-variants';

const progressVariants = tv({
  slots: {
    base: 'flex flex-col gap-1.5 w-full',
    labelContainer: 'flex justify-between items-center text-sm font-medium',
    root: 'relative w-full overflow-hidden rounded-full bg-secondary',
    indicator: 'rounded-full h-full w-full flex-1 transition-all duration-500 ease-in-out relative overflow-hidden flex items-center justify-end',
    innerLabel: 'text-[10px] font-bold text-white drop-shadow-md pr-2',
  },
  variants: {
    size: {
      sm: { root: 'h-3', innerLabel: 'text-[10px] pr-1' },
      md: { root: 'h-4', innerLabel: 'text-[10px] pr-1' },
      lg: { root: 'h-6', innerLabel: 'text-xs pr-3' },
    },
    variant: {
      default: { indicator: 'bg-primary' },
      success: { indicator: 'bg-success' },
      warning: { indicator: 'bg-warning' },
      danger: { indicator: 'bg-danger' },
      gradient: { indicator: 'bg-gradient-to-r from-primary to-indigo-400' },
    },
    striped: {
      true: { 
        indicator: 'bg-[linear-gradient(45deg,rgba(255,255,255,0.15)_25%,transparent_25%,transparent_50%,rgba(255,255,255,0.15)_50%,rgba(255,255,255,0.15)_75%,transparent_75%,transparent)] bg-[length:1rem_1rem]' 
      }
    },
    animated: {
      true: {
        indicator: 'animate-progress-stripes'
      }
    }
  },
  defaultVariants: {
    size: 'md',
    variant: 'default',
  }
});

/** Props for the Progress component */
export interface ProgressProps
  extends Omit<React.ComponentPropsWithoutRef<typeof BaseProgress.Root>, 'value'>,
    VariantProps<typeof progressVariants> {
    className?: string;
    /** Progress value from 0 to 100 */
    value?: number | null;
    /** @deprecated Use `labelPosition` instead */
    showLabel?: boolean;
    /** Where to display the percentage label */
    labelPosition?: 'inside' | 'outside' | 'none';
    /** Descriptive text label shown above the progress bar */
    label?: string;
}

const Progress = React.forwardRef<React.ElementRef<typeof BaseProgress.Root>, ProgressProps>(
  ({ className, value, size, variant, striped, animated, showLabel = false, labelPosition = 'none', label, ...props }, ref) => {
    const { base, root, indicator, labelContainer, innerLabel } = progressVariants({ size, variant, striped, animated });
    
    // Auto-enable striped if string animated is true, unless explicitly turned off
    const isStriped = striped !== undefined ? striped : animated;
    const { indicator: finalIndicator } = progressVariants({ size, variant, striped: isStriped, animated });

    const displayValue = value ?? 0;

    return (
      <div className={base({ className })}>
        {(labelPosition === 'outside' || label) && (
          <div className={labelContainer()}>
            {label && <span>{label}</span>}
            {labelPosition === 'outside' && <span>{Math.round(displayValue)}%</span>}
          </div>
        )}
        <BaseProgress.Root
          ref={ref}
          className={root()}
          value={value ?? null}
          aria-valuemin={0}
          aria-valuemax={100}
          aria-valuenow={displayValue}
          aria-label={label ?? 'Progress'}
          {...props}
        >
          <BaseProgress.Indicator 
            className={finalIndicator()} 
            style={{ transform: `translateX(-${100 - displayValue}%)` }} 
          >
            {labelPosition === 'inside' && displayValue > 5 && (
              <span className={innerLabel()}>{Math.round(displayValue)}%</span>
            )}
          </BaseProgress.Indicator>
        </BaseProgress.Root>
      </div>
    )
  }
)
Progress.displayName = 'Progress';

export { Progress };

import * as React from 'react';
import { QRCodeSVG, QRCodeCanvas } from 'qrcode.react';
import { Download } from 'lucide-react';
import { cn } from '@/lib/utils/cn';
import { Button } from '../button/Button';

// ─── Types ────────────────────────────────────────────────────────────────────
export type QRCodeLevel = 'L' | 'M' | 'Q' | 'H';
export type QRCodeRenderer = 'svg' | 'canvas';

export interface QRCodeImageSettings {
  src: string;
  width: number;
  height: number;
  excavate?: boolean;
  x?: number;
  y?: number;
  opacity?: number;
  crossOrigin?: 'anonymous' | 'use-credentials' | '';
}

const PIXEL_SIZE = { sm: 96, md: 128, lg: 192, xl: 256 } as const;

// ─── Props ────────────────────────────────────────────────────────────────────
export interface QRCodeProps {
  /** Value to encode — URL, text, etc. */
  value: string;
  /** Preset size: sm=96 md=128 lg=192 xl=256 */
  size?: keyof typeof PIXEL_SIZE;
  /** Override pixel dimension, takes precedence over size */
  pixelSize?: number;
  /** Error correction level — higher = more redundancy but denser pattern */
  level?: QRCodeLevel;
  /** Background color (hex/rgb string) */
  bgColor?: string;
  /** Foreground / module color (hex/rgb string) */
  fgColor?: string;
  /** Quiet zone modules around the QR code */
  marginSize?: number;
  /** Embed an image or logo in the center (use level H for best results) */
  imageSettings?: QRCodeImageSettings;
  /** SVG (crisp at any scale) or Canvas (downloadable as PNG) */
  renderer?: QRCodeRenderer;
  /** Accessible title for screen readers */
  title?: string;
  /** Label displayed above the QR code */
  label?: string;
  /** Caption displayed below the QR code */
  description?: string;
  /** Show a download button */
  downloadable?: boolean;
  /** Filename without extension used when downloading */
  downloadFilename?: string;
  className?: string;
  style?: React.CSSProperties;
}

// ─── Component ────────────────────────────────────────────────────────────────
export const QRCode = React.forwardRef<HTMLDivElement, QRCodeProps>(({
  value,
  size = 'md',
  pixelSize,
  level = 'L',
  bgColor = '#ffffff',
  fgColor = '#000000',
  marginSize = 2,
  imageSettings,
  renderer = 'svg',
  title,
  label,
  description,
  downloadable = false,
  downloadFilename = 'qrcode',
  className,
  style,
}, ref) => {
  const qrWrapperRef = React.useRef<HTMLDivElement>(null);
  const resolvedSize = pixelSize ?? PIXEL_SIZE[size];

  const handleDownload = React.useCallback(() => {
    const el = qrWrapperRef.current;
    if (!el) return;

    if (renderer === 'canvas') {
      const canvas = el.querySelector('canvas');
      if (!canvas) return;
      const link = document.createElement('a');
      link.download = `${downloadFilename}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
      return;
    }

    const svg = el.querySelector('svg');
    if (!svg) return;
    const blob = new Blob([svg.outerHTML], { type: 'image/svg+xml' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.download = `${downloadFilename}.svg`;
    link.href = url;
    link.click();
    URL.revokeObjectURL(url);
  }, [renderer, downloadFilename]);

  const qrProps = {
    value,
    size: resolvedSize,
    level,
    bgColor,
    fgColor,
    marginSize,
    imageSettings: imageSettings
      ? { excavate: false, ...imageSettings }
      : undefined,
    title: title ?? `QR Code: ${value}`,
  };

  return (
