'use client';

import * as React from 'react';
import { tv, type VariantProps } from 'tailwind-variants';
import { Star } from 'lucide-react';

const rateVariants = tv({
  slots: {
    root: 'inline-flex items-center gap-0.5',
    star: 'relative cursor-pointer transition-transform duration-100 hover:scale-110 focus:outline-none focus-visible:ring-2 focus-visible:ring-primary rounded-sm',
    starIcon: 'transition-colors duration-150',
  },
  variants: {
    size: {
      sm: { star: 'w-4 h-4', starIcon: 'w-4 h-4' },
      md: { star: 'w-6 h-6', starIcon: 'w-6 h-6' },
      lg: { star: 'w-8 h-8', starIcon: 'w-8 h-8' },
      xl: { star: 'w-10 h-10', starIcon: 'w-10 h-10' },
    },
    readonly: {
      true: { star: 'cursor-default hover:scale-100' },
    },
  },
  defaultVariants: {
    size: 'md',
  },
});

/** Props for the Rate component */
export interface RateProps extends VariantProps<typeof rateVariants> {
  /** Controlled rating value */
  value?: number;
  /** Default rating value (uncontrolled) */
  defaultValue?: number;
  /** Callback fired when the rating changes */
  onChange?: (value: number) => void;
  /** Total number of stars */
  count?: number;
  /** Allow half-star precision */
  allowHalf?: boolean;
  /** Allow clicking the current value to reset to 0 */
  allowClear?: boolean;
  /** Display as read-only (no interaction) */
  readonly?: boolean;
  /** Disable the rating component */
  disabled?: boolean;
  /** Custom element to render instead of the default star icon */
  character?: React.ReactNode;
  /** Tailwind text color class for filled stars */
  activeColor?: string;
  /** Tailwind text color class for empty stars */
  inactiveColor?: string;
  className?: string;
  /** Accessible label for the rating group */
  'aria-label'?: string;
  /**
   * Custom label for individual stars.
   * Receives the star index (1-based) and returns a string.
   * Defaults to "1 star", "2 stars", etc.
   */
  getStarLabel?: (index: number) => string;
}

const Rate = React.forwardRef<HTMLDivElement, RateProps>(({
  value: controlledValue,
  defaultValue = 0,
  onChange,
  count = 5,
  allowHalf = false,
  allowClear = true,
  readonly = false,
  disabled = false,
  character,
  activeColor = 'text-amber-400',
  inactiveColor = 'text-muted-foreground/30',
  size,
  className,
  'aria-label': ariaLabel,
  getStarLabel,
}, ref) => {
  const isControlled = controlledValue !== undefined;
  const [internalValue, setInternalValue] = React.useState(defaultValue);
  const [hoverValue, setHoverValue] = React.useState<number | null>(null);

  const value = isControlled ? controlledValue! : internalValue;

  const handleChange = (newVal: number) => {
    if (readonly || disabled) return;
    const next = allowClear && newVal === value ? 0 : newVal;
    if (!isControlled) setInternalValue(next);
    onChange?.(next);
  };

  const defaultGetStarLabel = (index: number) =>
    index === 1 ? '1 star' : `${index} stars`;

  const resolveLabel = getStarLabel ?? defaultGetStarLabel;

  const getStarFraction = (starIndex: number, displayValue: number): number => {
    const full = starIndex + 1;
    const half = starIndex + 0.5;
    if (displayValue >= full) return 1;
    if (allowHalf && displayValue >= half) return 0.5;
    return 0;
  };

  const slots = rateVariants({ size, readonly: readonly || disabled });
  const display = hoverValue ?? value;

  return (
    <div
      ref={ref}
      className={slots.root({ className })}
      role="radiogroup"
      aria-label={ariaLabel || 'Rating'}
    >
      {Array.from({ length: count }, (_, i) => {
        const fraction = getStarFraction(i, display);
        const full = i + 1;
        const half = i + 0.5;

        const renderStar = (frac: number) => {
          if (character) {
            if (frac === 0.5) {
              return (
                <span className="relative inline-flex items-center justify-center w-full h-full">
                  <span className={`absolute inset-0 overflow-hidden ${inactiveColor}`}>{character}</span>
                  <span className="absolute inset-0 overflow-hidden w-1/2" style={{ color: 'inherit' }}>
                    <span className={activeColor}>{character}</span>
                  </span>
                </span>
              );
            }
            return <span className={frac === 1 ? activeColor : inactiveColor}>{character}</span>;
          }

          if (frac === 0.5) {
            return (
              <span className="relative inline-flex items-center justify-center w-full h-full">
                <Star className={`${slots.starIcon()} ${inactiveColor}`} fill="currentColor" />
                <span
                  className="absolute inset-0 overflow-hidden"
                  style={{ width: '50%' }}
                  aria-hidden="true"
                >
                  <Star className={`${slots.starIcon()} ${activeColor}`} fill="currentColor" />
                </span>
              </span>
            );
          }

          return (
            <Star
              className={`${slots.starIcon()} ${frac === 1 ? activeColor : inactiveColor}`}
              fill="currentColor"
            />
          );
        };

        return (
          <button
            key={i}
            type="button"
            role="radio"
            aria-checked={full <= value}
            aria-label={resolveLabel(full)}
            disabled={disabled}
            className={slots.star()}
            onMouseMove={(e) => {
              if (readonly || disabled) return;
              if (allowHalf) {
                const rect = e.currentTarget.getBoundingClientRect();
                const isLeft = e.clientX - rect.left < rect.width / 2;
                setHoverValue(isLeft ? half : full);
              } else {
                setHoverValue(full);
              }
            }}
            onMouseLeave={() => setHoverValue(null)}
            onClick={(e) => {
              if (readonly || disabled) return;
              if (allowHalf) {
                const rect = e.currentTarget.getBoundingClientRect();
                const isLeft = e.clientX - rect.left < rect.width / 2;
                handleChange(isLeft ? half : full);
              } else {
                handleChange(full);
              }
            }}
            onKeyDown={(e) => {
              if (readonly || disabled) return;
              if (e.key === 'ArrowRight' || e.key === 'ArrowUp') {
                e.preventDefault();
                handleChange(Math.min(count, value + (allowHalf ? 0.5 : 1)));
              } else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') {
                e.preventDefault();
                handleChange(Math.max(0, value - (allowHalf ? 0.5 : 1)));
              }
            }}
          >
            {renderStar(fraction)}
          </button>
        );
      })}
    </div>
  );
});

Rate.displayName = 'Rate';

export { Rate };

import * as React from 'react';
import { Group, Panel, Separator } from 'react-resizable-panels';
import type { GroupProps, PanelProps, SeparatorProps } from 'react-resizable-panels';
import { tv, type VariantProps } from 'tailwind-variants';
import { cn } from '@/lib/utils/cn';

// ─── Direction Context ────────────────────────────────────────

interface ResizableContextValue {
  direction: 'horizontal' | 'vertical';
}

const ResizableContext = React.createContext<ResizableContextValue>({
  direction: 'horizontal',
});

// ─── Grip Dots ────────────────────────────────────────────────

function GripDots({ isVerticalHandle, className }: { isVerticalHandle: boolean; className?: string }) {
  if (isVerticalHandle) {
    return (
      <div className={cn('flex flex-col gap-[3px]', className)}>
        {[0, 1, 2].map((r) => (
          <div key={r} className="flex gap-[3px]">
            <div className="w-[3px] h-[3px] rounded-full bg-current" />
            <div className="w-[3px] h-[3px] rounded-full bg-current" />
          </div>
        ))}
      </div>
    );
  }
  return (
    <div className={cn('flex gap-[3px]', className)}>
      {[0, 1, 2].map((c) => (
        <div key={c} className="flex flex-col gap-[3px]">
          <div className="w-[3px] h-[3px] rounded-full bg-current" />
          <div className="w-[3px] h-[3px] rounded-full bg-current" />
        </div>
      ))}
    </div>
  );
}

// ─── Handle Variants ─────────────────────────────────────────

const handleVariants = tv({
  base: [
    'relative flex items-center justify-center shrink-0',
    'select-none touch-none outline-none',
    'group/handle',
  ].join(' '),
  variants: {
    variant: {
      line: '',
      bar: '',
      handle: '',
      ghost: '',
    },
  },
  defaultVariants: { variant: 'line' },
});

// ─── Types ────────────────────────────────────────────────────

export type ResizablePanelGroupProps = Omit<GroupProps, 'orientation'> & {
  direction?: 'horizontal' | 'vertical';
};

export type ResizablePanelProps = PanelProps;

export type ResizableHandleProps = Omit<SeparatorProps, 'className'> &
  VariantProps<typeof handleVariants> & {
    withGrip?: boolean;
    className?: string;
  };

// ─── ResizablePanelGroup ──────────────────────────────────────

function ResizablePanelGroup({
  direction = 'horizontal',
  className,
  children,
  ...props
}: ResizablePanelGroupProps) {
  return (
    <ResizableContext.Provider value={{ direction }}>
      <Group
        orientation={direction}
        className={cn('flex h-full w-full data-[panel-group-direction=vertical]:flex-col', className)}
        {...props}
      >
        {children}
      </Group>
    </ResizableContext.Provider>
  );
}
ResizablePanelGroup.displayName = 'ResizablePanelGroup';

// ─── ResizablePanel ───────────────────────────────────────────

function ResizablePanel({ className, ...props }: ResizablePanelProps) {
  return <Panel className={cn('overflow-auto', className)} {...props} />;
}
ResizablePanel.displayName = 'ResizablePanel';

// ─── ResizableHandle ─────────────────────────────────────────

function ResizableHandle({
  variant = 'line',
  withGrip = false,
  className,
  disabled,
  ...props
}: ResizableHandleProps) {
  const { direction } = React.useContext(ResizableContext);
  const [isDragging, setIsDragging] = React.useState(false);

  const isVerticalHandle = direction === 'horizontal';

  // Shared thin-line indicator position styles
  const linePos = isVerticalHandle
    ? 'absolute inset-y-0 left-1/2 -translate-x-1/2 w-px'
    : 'absolute inset-x-0 top-1/2 -translate-y-1/2 h-px';

  return (
    <Separator
      disabled={disabled}
      onPointerDown={() => setIsDragging(true)}
      onPointerUp={() => setIsDragging(false)}
      onPointerLeave={() => setIsDragging(false)}
      className={cn(
        handleVariants({ variant }),

        // ── orientation & cursor ──────────────────────────────
        isVerticalHandle
          ? 'h-full cursor-col-resize'
          : 'w-full cursor-row-resize',

        // ── per-variant zone width ────────────────────────────
        // line: 4 px transparent zone
        variant === 'line' && (isVerticalHandle ? 'w-1' : 'h-1'),

        // bar: 8 px transparent zone — easy to grab anywhere along sidebar edge
        variant === 'bar' && (isVerticalHandle ? 'w-2' : 'h-2'),

        // handle: 12 px zone with visible pill on hover
        variant === 'handle' && (isVerticalHandle ? 'w-3' : 'h-3'),

        // ghost: 8 px invisible zone
        variant === 'ghost' && (isVerticalHandle ? 'w-2' : 'h-2'),

        // all non-ghost: transparent background
        variant !== 'ghost' && 'bg-transparent',

        // drag shadow — secondary tint
        isDragging && variant !== 'ghost' && 'shadow-[0_0_0_1px] shadow-secondary/30',

        className,
      )}
      {...props}
    >
      {/* ── LINE: thin border-colored line ────────────────── */}
      {variant === 'line' && (
        <div
          className={cn(
            linePos,
            'transition-colors duration-150 rounded-full',
            isDragging
              ? 'bg-secondary/70'
              : 'bg-border group-hover/handle:bg-secondary/50',
          )}
        />
      )}

      {/* ── BAR: full-height thin line + centered grip pill ── */}
      {variant === 'bar' && (
        <>
          {/* full-height thin line */}
          <div
            className={cn(
              linePos,
              'transition-colors duration-150',
              isDragging
                ? 'bg-secondary/60'
                : 'bg-border/70 group-hover/handle:bg-secondary/40',
            )}
          />
          {/* centered grip pill */}
          <div
            className={cn(
              'relative z-10 rounded-full transition-colors duration-150',
              isVerticalHandle ? 'w-[3px] h-6' : 'h-[3px] w-6',
              isDragging
                ? 'bg-secondary/70'
                : 'bg-muted-foreground/25 group-hover/handle:bg-secondary/50',
            )}
          />
        </>
      )}

      {/* ── HANDLE: bordered pill on hover ────────────────── */}
      {variant === 'handle' && (
        <div
          className={cn(
            'z-10 flex items-center justify-center rounded-sm border border-border bg-background',
            'opacity-0 group-hover/handle:opacity-100 transition-opacity duration-150',
            isDragging && 'opacity-100 border-secondary/60',
            'shadow-sm',
            isVerticalHandle ? 'w-5 h-8' : 'h-5 w-8',
          )}
        >
          <GripDots
            isVerticalHandle={isVerticalHandle}
            className={isDragging ? 'text-secondary/70' : 'text-muted-foreground/70'}
          />
        </div>
      )}

      {/* ── withGrip: overlay dots on line / ghost ─────────── */}
      {withGrip && variant !== 'handle' && variant !== 'bar' && (
        <div className="z-10 opacity-0 group-hover/handle:opacity-100 transition-opacity duration-150">
          <GripDots
            isVerticalHandle={isVerticalHandle}
            className="text-muted-foreground/50 group-hover/handle:text-muted-foreground/70 transition-colors"
          />
        </div>
      )}
    </Separator>
  );
}
ResizableHandle.displayName = 'ResizableHandle';

// ─── Exports ─────────────────────────────────────────────────

export {
  ResizablePanelGroup,
  ResizablePanel,
  ResizableHandle,
  handleVariants,
};

