    pageSizeOptions?: number[];
    showTotal?: (total: number, range: [number, number]) => React.ReactNode;
    showSizeChanger?: boolean;
    onChange?: (page: number, pageSize: number) => void;
}

export interface TableLabels {
    page?: string;
    perPage?: string;
    empty?: string;
}

export interface TableProps<TData, TValue = unknown> {
    data: TData[];
    columns: ColumnDef<TData, TValue>[];
    isLoading?: boolean;
    enableSorting?: boolean;
    enableRowSelection?: boolean;
    enableExpanding?: boolean;
    renderSubComponent?: (props: { row: TData }) => React.ReactNode;
    getRowCanExpand?: (row: TData) => boolean;
    onSelectionChange?: (selectedRows: TData[]) => void;
    className?: string;
    enableColumnResizing?: boolean;
    columnResizeMode?: ColumnResizeMode;
    pagination?: PaginationConfig | false;
    /** @deprecated Use `labels.empty` instead */
    emptyText?: string;
    labels?: TableLabels;
    virtualize?: boolean;
    virtualHeight?: number;
    estimatedRowHeight?: number;
}

export function Table<TData, TValue = unknown>({
    data = [],
    columns,
    isLoading = false,
    enableSorting = true,
    enableRowSelection = false,
    enableExpanding = false,
    renderSubComponent,
    getRowCanExpand,
    onSelectionChange,
    className,
    enableColumnResizing = false,
    columnResizeMode = 'onChange',
    pagination: paginationProp = {},
    emptyText,
    labels,
    virtualize = false,
    virtualHeight = 400,
    estimatedRowHeight = 45,
}: TableProps<TData>) {
    const resolvedEmptyText = emptyText ?? labels?.empty ?? 'No data';
    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const paginationEnabled = paginationProp !== false;
    const cfg = paginationEnabled ? (paginationProp as PaginationConfig) : {};

    const isServerMode = paginationEnabled && cfg.total !== undefined;
    const [page, setPage] = useState(cfg.current ?? 1);
    const [pageSize, setPageSize] = useState(cfg.pageSize ?? 10);

    useEffect(() => {
        if (cfg.current !== undefined) setPage(cfg.current);
    }, [cfg.current]);

    useEffect(() => {
        if (cfg.pageSize !== undefined) setPageSize(cfg.pageSize);
    }, [cfg.pageSize]);

    const pageIndex = page - 1;
    const totalRows = isServerMode ? cfg.total! : data.length;
    const pageCount = isServerMode ? Math.ceil(totalRows / pageSize) : undefined;
    const tanstackPagination: PaginationState = { pageIndex, pageSize };

    const handlePaginationChange = (updater: PaginationState | ((prev: PaginationState) => PaginationState)) => {
        const next = typeof updater === 'function' ? updater(tanstackPagination) : updater;
        const newPage = next.pageIndex + 1;
        const newPageSize = next.pageSize;

        if (!isServerMode) {
            setPage(newPage);
            setPageSize(newPageSize);
        }
        cfg.onChange?.(newPage, newPageSize);
    };

    const [sorting, setSorting] = useState<SortingState>([]);
    const [rowSelection, setRowSelection] = useState<RowSelectionState>({});

    const finalColumns = React.useMemo(() => {
        const cols = [...columns];
        if (enableRowSelection) {
            cols.unshift({
                id: 'select',
                size: 10,
                minSize: 5,
                maxSize: 10,
                meta: { align: 'center' },
                header: ({ table }) => (
                    <div className="flex items-center justify-center">
                        <Checkbox
                            size="sm"
                            checked={table.getIsAllRowsSelected()}
                            indeterminate={table.getIsSomeRowsSelected()}
                            onCheckedChange={(checked) => table.toggleAllRowsSelected(!!checked)}
                        />
                    </div>
                ),
                cell: ({ row }) => (
                    <div className="flex items-center justify-center">
                        <Checkbox
                            size="sm"
                            checked={row.getIsSelected()}
                            disabled={!row.getCanSelect()}
                            onCheckedChange={(checked) => row.toggleSelected(!!checked)}
                        />
                    </div>
                ),
                enableSorting: false,
            });
        }
        if (enableExpanding) {
            cols.unshift({
                id: 'expander',
                header: () => null,
                size: 10,
                minSize: 10,
                maxSize: 10,
                meta: { align: 'center' },
                cell: ({ row }) => row.getCanExpand() ? (
                    <div className="flex items-center justify-center">
                        <span
                            onClick={row.getToggleExpandedHandler()}
                            className="hover:bg-muted text-muted-foreground transition-colors cursor-pointer outline-none focus:ring-2 focus:ring-primary/50 p-1 rounded-md border border-border"
                        >
                            {row.getIsExpanded() ? <ChevronDown className="w-3 h-3" /> : <ChevronRight className="w-3 h-3" />}
                        </span>
                    </div>
                ) : null,
                enableSorting: false,
            });
        }
        return cols;
    }, [columns, enableRowSelection, enableExpanding]);

    const table = useReactTable({
        data,
        columns: finalColumns,
        state: { sorting, rowSelection, pagination: tanstackPagination },
        onSortingChange: setSorting,
        onRowSelectionChange: setRowSelection,
        onPaginationChange: handlePaginationChange,
        getCoreRowModel: getCoreRowModel(),
        getSortedRowModel: enableSorting ? getSortedRowModel() : undefined,
        getPaginationRowModel: paginationEnabled ? getPaginationRowModel() : undefined,
        getFilteredRowModel: getFilteredRowModel(),
        getExpandedRowModel: getExpandedRowModel(),
        columnResizeMode,
        enableColumnResizing,
        enableRowSelection,
        manualPagination: isServerMode,
        pageCount: isServerMode ? pageCount : undefined,
        getRowCanExpand: getRowCanExpand ? (row) => getRowCanExpand(row.original) : () => !!renderSubComponent,
    });

    useEffect(() => {
        if (onSelectionChange) {
            const selected = table.getSelectedRowModel().rows.map(row => row.original);
            onSelectionChange(selected);
        }
    }, [rowSelection, onSelectionChange, table]);

    const totalPageCount = isServerMode ? (pageCount ?? 1) : (table.getPageCount() || 1);

    // Virtualizer
    const allRows = virtualize ? table.getCoreRowModel().rows : [];
    const rowVirtualizer = useVirtualizer({
        count: virtualize ? allRows.length : 0,
        getScrollElement: () => scrollContainerRef.current,
        estimateSize: () => estimatedRowHeight,
        overscan: 8,
        enabled: virtualize,
    });

    return (
        <div className={cn("relative w-full rounded-md border border-border bg-background flex flex-col overflow-hidden", className)}>
            {isLoading && (
                <div className="absolute inset-0 bg-white/60 z-10 flex items-center justify-center backdrop-blur-[0.5px]">
                    <Spinner size="lg" variant="primary" />
                </div>
            )}

            <div
                ref={scrollContainerRef}
                className="overflow-x-auto w-full"
                style={virtualize ? { overflowY: 'auto', maxHeight: virtualHeight } : undefined}
            >
                <table
                    className="w-full text-sm text-left text-foreground whitespace-nowrap"
                    style={{
                        width: enableColumnResizing ? table.getCenterTotalSize() : undefined,
                        tableLayout: enableColumnResizing ? 'fixed' : 'auto'
                    }}
                >
                    <TableHeader
                        headerGroups={table.getHeaderGroups()}
                        enableSorting={enableSorting}
                        enableColumnResizing={enableColumnResizing}
                    />
                    <tbody>
                        {!isLoading && data.length === 0 ? (
                            <TableEmpty colSpan={finalColumns.length} text={resolvedEmptyText} />
                        ) : virtualize ? (
                            <TableVirtualRows
                                allRows={allRows}
                                rowVirtualizer={rowVirtualizer}
                                enableColumnResizing={enableColumnResizing}
                                colSpan={finalColumns.length}
                            />
                        ) : (
                            <TableNormalRows
                                rows={table.getRowModel().rows}
                                enableColumnResizing={enableColumnResizing}
                                renderSubComponent={renderSubComponent}
                            />
                        )}
                    </tbody>
                </table>
            </div>

            {!virtualize && paginationEnabled && (
                <TablePagination
                    table={table}
                    totalRows={totalRows}
                    totalPageCount={totalPageCount}
                    isServerMode={isServerMode}
                    cfg={cfg}
                    labels={labels}
                />
            )}
        </div>
    );
}

import React from 'react';
import {
    flexRender,
    type Row,
    type ColumnDef,
    type RowData,
} from '@tanstack/react-table';
import { useVirtualizer, type Virtualizer } from '@tanstack/react-virtual';
import { cn } from '@/lib/utils/cn';

// ─── Empty State ────────────────────────────────────────────────────────────

interface TableEmptyProps {
    colSpan: number;
    text: string;
}

export function TableEmpty({ colSpan, text }: TableEmptyProps) {
    return (
        <tr className="border-b border-border">
            <td colSpan={colSpan} className="px-4 py-16 text-center text-muted-foreground">
                <div className="flex flex-col items-center justify-center space-y-2">
                    <span className="text-muted-foreground/50">
                        <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-3.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4" />
                        </svg>
                    </span>
                    <span>{text}</span>
                </div>
            </td>
        </tr>
    );
}

// ─── Row Cell Renderer ──────────────────────────────────────────────────────

interface TableRowCellsProps<TData extends RowData> {
    row: Row<TData>;
    enableColumnResizing: boolean;
}

function TableRowCells<TData extends RowData>({ row, enableColumnResizing }: TableRowCellsProps<TData>) {
    const visibleCells = row.getVisibleCells();
    return (
        <>
            {visibleCells.map((cell, index) => {
                const meta = cell.column.columnDef.meta;
                const align = meta?.align || 'left';
                const isLastColumn = index === visibleCells.length - 1;
                return (
                    <td
                        key={cell.id}
                        style={{ width: enableColumnResizing ? cell.column.getSize() : cell.column.columnDef.size }}
                        className={cn(
                            cell.column.id === 'select' || cell.column.id === 'expander' ? "px-1" : "px-2",
                            "py-3 align-middle",
                            align === 'center' ? "text-center" : align === 'right' ? "text-right" : "text-left",
                            !isLastColumn && "border-r border-border"
                        )}
                    >
                        <div className={cn(
                            "flex items-center",
                            align === 'center' ? "justify-center" : align === 'right' ? "justify-end" : "justify-start"
                        )}>
                            {flexRender(cell.column.columnDef.cell, cell.getContext())}
                        </div>
                    </td>
                );
            })}
        </>
    );
}

// ─── Normal Rows ────────────────────────────────────────────────────────────

interface TableNormalRowsProps<TData extends RowData> {
    rows: Row<TData>[];
    enableColumnResizing: boolean;
    renderSubComponent?: (props: { row: TData }) => React.ReactNode;
}

export function TableNormalRows<TData extends RowData>({
    rows,
    enableColumnResizing,
    renderSubComponent,
}: TableNormalRowsProps<TData>) {
    return (
        <>
            {rows.map(row => (
                <React.Fragment key={row.id}>
                    <tr
                        className={cn(
                            "border-b border-border hover:bg-muted/50 transition-colors group",
                            row.getIsSelected() ? "bg-primary/5 hover:bg-primary/10" : "",
                            row.getIsExpanded() ? "bg-primary/5" : ""
                        )}
                    >
                        <TableRowCells row={row} enableColumnResizing={enableColumnResizing} />
                    </tr>
                    {row.getIsExpanded() && renderSubComponent && (
                        <tr className="border-b border-border">
                            <td colSpan={row.getVisibleCells().length} className="p-0 whitespace-normal">
                                <div className="bg-muted/50 px-4 py-5 shadow-inner w-full border-l-4 border-l-primary/40 wrap-break-word">
                                    {renderSubComponent({ row: row.original })}
                                </div>
                            </td>
                        </tr>
                    )}
                </React.Fragment>
            ))}
        </>
    );
}

// ─── Virtual Rows ───────────────────────────────────────────────────────────

interface TableVirtualRowsProps<TData extends RowData> {
    allRows: Row<TData>[];
    rowVirtualizer: Virtualizer<HTMLDivElement, Element>;
    enableColumnResizing: boolean;
    colSpan: number;
}

export function TableVirtualRows<TData extends RowData>({
    allRows,
    rowVirtualizer,
    enableColumnResizing,
    colSpan,
}: TableVirtualRowsProps<TData>) {
    const virtualItems = rowVirtualizer.getVirtualItems();

    return (
        <>
            {rowVirtualizer.getTotalSize() > 0 && (
                <tr aria-hidden="true">
                    <td style={{ height: virtualItems[0]?.start ?? 0, padding: 0, border: 0 }} colSpan={colSpan} />
                </tr>
            )}
            {virtualItems.map(virtualRow => {
                const row = allRows[virtualRow.index];
                if (!row) return null;
                return (
                    <tr
                        key={row.id}
                        data-index={virtualRow.index}
                        ref={rowVirtualizer.measureElement}
                        className={cn(
                            "border-b border-border hover:bg-muted/50 transition-colors",
                            row.getIsSelected() ? "bg-primary/5 hover:bg-primary/10" : ""
                        )}
                    >
                        <TableRowCells row={row} enableColumnResizing={enableColumnResizing} />
                    </tr>
                );
            })}
            {rowVirtualizer.getTotalSize() > 0 && (
                <tr aria-hidden="true">
                    <td
                        style={{
                            height: rowVirtualizer.getTotalSize() - (virtualItems[virtualItems.length - 1]?.end ?? 0),
                            padding: 0,
                            border: 0,
                        }}
                        colSpan={colSpan}
                    />
                </tr>
            )}
        </>
    );
}

import React from 'react';
import {
    flexRender,
    type HeaderGroup,
    type RowData,
} from '@tanstack/react-table';
import { cn } from '@/lib/utils/cn';
import { ChevronDown, ChevronUp } from 'lucide-react';

export interface TableHeaderProps<TData extends RowData> {
    headerGroups: HeaderGroup<TData>[];
    enableSorting: boolean;
    enableColumnResizing: boolean;
}

export function TableHeader<TData extends RowData>({
    headerGroups,
    enableSorting,
    enableColumnResizing,
}: TableHeaderProps<TData>) {
    return (
        <thead className="text-xs text-muted-foreground bg-muted/50 border-b border-border">
            {headerGroups.map(headerGroup => (
                <tr key={headerGroup.id} className="border-b border-border">
                    {headerGroup.headers.map((header, index) => {
                        const meta = header.column.columnDef.meta;
                        const align = meta?.align || 'left';
                        const canSort = header.column.getCanSort() && enableSorting && header.column.id !== 'select';
                        const isLastColumn = index === headerGroup.headers.length - 1;

                        return (
                            <th
                                key={header.id}
                                colSpan={header.colSpan}
                                style={{
                                    width: enableColumnResizing ? header.getSize() : header.column.columnDef.size,
                                    position: 'relative'
                                }}
                                aria-sort={
                                    canSort
                                        ? header.column.getIsSorted() === 'desc'
                                            ? 'descending'
                                            : header.column.getIsSorted() === 'asc'
                                                ? 'ascending'
                                                : 'none'
                                        : undefined
                                }
                                className={cn(
                                    header.column.id === 'select' || header.column.id === 'expander' ? "px-1" : "px-2",
                                    "py-3 font-semibold tracking-wide  transition-colors group/header",
                                    canSort ? "cursor-pointer select-none hover:bg-muted" : "",
                                    align === 'center' ? "text-center" : align === 'right' ? "text-right" : "text-left",
                                    !isLastColumn && "border-r border-border"
                                )}
                            >
                                <div
                                    className={cn("flex flex-col h-full")}
                                    onClick={canSort ? header.column.getToggleSortingHandler() : undefined}
                                >
                                    {header.isPlaceholder ? null : (
                                        <div className={cn(
                                            "flex items-center gap-2",
                                            align === 'center' ? "justify-center" : align === 'right' ? "justify-end" : "justify-between"
                                        )}>
                                            <span>{flexRender(header.column.columnDef.header, header.getContext())}</span>
                                            {canSort && (
                                                <span className="shrink-0">
                                                    {{
                                                        asc: <ChevronUp className="w-4 h-4 text-primary" />,
                                                        desc: <ChevronDown className="w-4 h-4 text-primary" />,
                                                    }[header.column.getIsSorted() as string] ?? (
                                                            <div className="flex flex-col opacity-30 -space-y-1 hover:opacity-100 transition-opacity">
                                                                <ChevronUp className="w-3 h-3" />
                                                                <ChevronDown className="w-3 h-3" />
                                                            </div>
                                                        )}
                                                </span>
                                            )}
                                        </div>
                                    )}
                                </div>

                                {/* Resize Handle */}
                                {enableColumnResizing && header.column.getCanResize() && (
                                    <div
                                        {...{
                                            onMouseDown: header.getResizeHandler(),
                                            onTouchStart: header.getResizeHandler(),
                                            className: cn(
                                                "absolute right-0 top-0 h-full w-1 cursor-col-resize select-none touch-none hover:bg-primary/50 transition-colors",
                                                header.column.getIsResizing() ? "bg-primary w-1.5 z-10" : "bg-transparent"
                                            ),
                                        }}
                                    />
                                )}
                            </th>
                        );
                    })}
                </tr>
            ))}
        </thead>
    );
}

import React, { useState, useEffect } from 'react';
import { type Table as TanstackTable, type RowData } from '@tanstack/react-table';
import { ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from 'lucide-react';
import type { PaginationConfig, TableLabels } from './Table';

interface TablePaginationProps<TData extends RowData> {
    table: TanstackTable<TData>;
    totalRows: number;
    totalPageCount: number;
    isServerMode: boolean;
    cfg: PaginationConfig;
    labels?: TableLabels;
}

export function TablePagination<TData extends RowData>({
    table,
    totalRows,
    totalPageCount,
    isServerMode,
    cfg,
    labels,
}: TablePaginationProps<TData>) {
    const currentPageIndex = table.getState().pagination.pageIndex;
    const currentPageSize = table.getState().pagination.pageSize;
    const from = currentPageIndex * currentPageSize + 1;
    const to = Math.min((currentPageIndex + 1) * currentPageSize, totalRows);
    const pageSizeOptions = cfg.pageSizeOptions ?? [5, 10, 20, 50, 100];

    const [inputValue, setInputValue] = useState<string | number>(currentPageIndex + 1);

    useEffect(() => {
        setInputValue(currentPageIndex + 1);
    }, [currentPageIndex]);

    if (totalPageCount <= 0) return null;

    return (
        <div className="flex flex-col sm:flex-row items-center justify-between px-3 py-2.5 border-t border-border bg-muted/50 gap-2">
            {/* showTotal info */}
            <div className="text-xs text-muted-foreground shrink-0 order-2 sm:order-1">
                {cfg.showTotal
                    ? cfg.showTotal(totalRows, [from, to])
                    : <>Show <b>{from}</b>–<b>{to}</b> of <b>{totalRows}</b> results</>
                }
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2 overflow-x-auto order-1 sm:order-2 w-full sm:w-auto pb-0.5 sm:pb-0">
                {/* Page size */}
                {(cfg.showSizeChanger !== false) && (
                    <select
                        value={currentPageSize}
                        onChange={e => table.setPageSize(Number(e.target.value))}
                        className="shrink-0 px-2 py-1 text-xs border border-border rounded-md bg-background text-foreground outline-none focus:border-primary focus:ring-1 focus:ring-primary cursor-pointer"
                    >
                        {pageSizeOptions.map(s => (
                            <option key={s} value={s}>{s}{labels?.perPage ?? ' / page'}</option>
                        ))}
                    </select>
                )}

                {/* Nav buttons */}
                <div className="flex items-center gap-1 shrink-0">
                    <button
                        className="p-1 rounded border border-border text-muted-foreground bg-background hover:bg-muted disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                        onClick={() => table.setPageIndex(0)}
                        disabled={!table.getCanPreviousPage()}
                        aria-label="First page"
                    >
                        <ChevronsLeft className="w-3.5 h-3.5" />
                    </button>
                    <button
                        className="p-1 rounded border border-border text-muted-foreground bg-background hover:bg-muted disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                        onClick={() => table.previousPage()}
                        disabled={!table.getCanPreviousPage()}
                        aria-label="Previous page"
                    >
                        <ChevronLeft className="w-3.5 h-3.5" />
                    </button>

                    <span className="text-xs font-medium px-2.5 py-1 bg-background border border-border rounded shrink-0 min-w-14 text-center text-foreground">
                        {currentPageIndex + 1} / {totalPageCount}
                    </span>

                    <button
                        className="p-1 rounded border border-border text-muted-foreground bg-background hover:bg-muted disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                        onClick={() => table.nextPage()}
                        disabled={!table.getCanNextPage()}
                        aria-label="Next page"
                    >
                        <ChevronRight className="w-3.5 h-3.5" />
                    </button>
                    <button
                        className="p-1 rounded border border-border text-muted-foreground bg-background hover:bg-muted disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                        onClick={() => table.setPageIndex(totalPageCount - 1)}
                        disabled={!table.getCanNextPage()}
                        aria-label="Last page"
                    >
                        <ChevronsRight className="w-3.5 h-3.5" />
                    </button>
                </div>

                {/* Go to page */}
                <div className="flex items-center gap-1.5 text-xs text-muted-foreground border-l border-border pl-2 ml-1 shrink-0">
                    <span className="hidden sm:inline">{labels?.page ?? 'Page'}</span>
                    <input
                        type="number"
                        min={1}
                        max={totalPageCount}
                        value={inputValue}
                        onChange={e => {
                            const val = e.target.value;
                            setInputValue(val);
                            const p = val ? Number(val) - 1 : 0;
                            if (val && p >= 0 && p < totalPageCount) {
                                table.setPageIndex(p);
                            }
                        }}
                        onBlur={() => setInputValue(currentPageIndex + 1)}
                        className="w-10 px-1 py-1 text-xs border border-border rounded bg-background text-foreground text-center outline-none focus:border-primary focus:ring-1 focus:ring-primary"
                    />
                </div>
            </div>
        </div>
    );
}

import * as React from 'react';
import { cn } from '@/lib/utils/cn';

// ─── Types ────────────────────────────────────────────────────────────────────
export type TocItem = {
  id: string;
  label: string;
  level?: 1 | 2 | 3;
};

export interface TableContentsProps {
  items: TocItem[];
  /** Offset (px) từ top khi scroll — dành cho sticky header */
  offset?: number;
  /** Title hiển thị trên danh sách */
  title?: string;
  className?: string;
}

// ─── Helper: tìm scrollable ancestor gần nhất ────────────────────────────────
function getScrollParent(el: HTMLElement | null): HTMLElement | null {
  let node = el?.parentElement ?? null;
  while (node && node !== document.body) {
    const { overflow, overflowY } = getComputedStyle(node);
    if (/auto|scroll/.test(overflow + overflowY)) return node;
    node = node.parentElement;
  }
  return null;
}

// ─── Hook: theo dõi section đang active qua IntersectionObserver ──────────────
function useActiveSection(ids: string[], offset: number): string {
  const [activeId, setActiveId] = React.useState('');

  React.useEffect(() => {
    if (!ids.length) return;

    // Dùng scrollable container làm root để rootMargin hoạt động đúng
    const firstEl = document.getElementById(ids[0]);
    const root = firstEl ? getScrollParent(firstEl) : null;

    const observer = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          if (entry.isIntersecting) {
            setActiveId(entry.target.id);
            break;
          }
        }
      },
      { root, rootMargin: `-${offset + 8}px 0px -70% 0px`, threshold: 0 },
    );

    ids.forEach((id) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, [ids, offset]);

  return activeId;
}

// ─── Component ────────────────────────────────────────────────────────────────
export const TableContents: React.FC<TableContentsProps> = ({
  items,
  offset = 80,
  title = 'Trên trang này',
  className,
}) => {
  const ids = React.useMemo(() => items.map((i) => i.id), [items]);
  const activeId = useActiveSection(ids, offset);

  const scrollTo = (id: string) => {
    const el = document.getElementById(id);
    if (!el) return;

    const container = getScrollParent(el);
    if (!container) {
      // Fallback: window scroll
      window.scrollTo({
        top: el.getBoundingClientRect().top + window.scrollY - offset,
        behavior: 'smooth',
      });
      return;
    }

    const top =
      el.getBoundingClientRect().top -
      container.getBoundingClientRect().top +
      container.scrollTop -
      offset;
    container.scrollTo({ top, behavior: 'smooth' });
  };

  return (
    <nav className={cn('select-none', className)} aria-label="Table of contents">
      {title && (
        <p className="mb-3 text-xs font-semibold uppercase tracking-widest text-muted-foreground">
          {title}
        </p>
      )}

      <ul className="space-y-0.5 border-l border-border">
        {items.map((item) => {
          const level = item.level ?? 1;
          const isActive = activeId === item.id;

          return (
            <li key={item.id}>
              <button
                onClick={() => scrollTo(item.id)}
                className={cn(
                  'block w-full text-left text-sm leading-5 transition-all duration-150',
                  'py-1 pr-2 hover:text-foreground',
                  // Indentation theo level
                  level === 1 && 'pl-3 font-medium',
                  level === 2 && 'pl-5 font-normal',
                  level === 3 && 'pl-8 font-normal text-xs',
                  // Border left indicator
                  isActive
                    ? '-ml-px border-l-2 border-primary pl-[calc(theme(spacing.3)-1px)] text-primary'
                    : 'text-muted-foreground',
                  level === 2 && isActive && 'pl-[calc(theme(spacing.5)-1px)]',
                  level === 3 && isActive && 'pl-[calc(theme(spacing.8)-1px)]',
                )}
                aria-current={isActive ? 'location' : undefined}
              >
                {item.label}
              </button>
            </li>
          );
        })}
      </ul>
    </nav>
  );
};

