import * as React from 'react';
import { tv, type VariantProps } from 'tailwind-variants';
import { cn } from '@/lib/utils/cn';
import { Copy, Check, ExternalLink } from 'lucide-react';
import { useCopy } from '@/hooks/useCopy';

// ─── Shared text style variants ───────────────────────────────────────────────

const textVariants = tv({
  base: '',
  variants: {
    size: {
      xs:   'text-xs',
      sm:   'text-sm',
      md:   'text-base',
      lg:   'text-lg',
      xl:   'text-xl',
      '2xl': 'text-2xl',
      '3xl': 'text-3xl',
    },
    weight: {
      thin:      'font-thin',
      light:     'font-light',
      normal:    'font-normal',
      medium:    'font-medium',
      semibold:  'font-semibold',
      bold:      'font-bold',
      extrabold: 'font-extrabold',
    },
    color: {
      default: 'text-foreground',
      muted:   'text-muted-foreground',
      primary: 'text-primary',
      success: 'text-success',
      warning: 'text-warning',
      danger:  'text-danger',
      inherit: 'text-inherit',
    },
    align: {
      left:    'text-left',
      center:  'text-center',
      right:   'text-right',
      justify: 'text-justify',
    },
    leading: {
      none:    'leading-none',
      tight:   'leading-tight',
      normal:  'leading-normal',
      relaxed: 'leading-relaxed',
      loose:   'leading-loose',
    },
    tracking: {
      tighter: 'tracking-tighter',
      tight:   'tracking-tight',
      normal:  'tracking-normal',
      wide:    'tracking-wide',
      widest:  'tracking-widest',
    },
  },
  defaultVariants: {
    color: 'default',
  },
});

// ─── Text ─────────────────────────────────────────────────────────────────────

export interface TextProps
  extends Omit<React.HTMLAttributes<HTMLElement>, 'color'>,
    VariantProps<typeof textVariants> {
  /** HTML tag to render — default `span` */
  as?: React.ElementType;
  /** Bold */
  strong?: boolean;
  /** Italic */
  italic?: boolean;
  /** Underline */
  underline?: boolean;
  /** Strikethrough */
  strikethrough?: boolean;
  /** Gradient text (primary → indigo) */
  gradient?: boolean;
  /** Highlighted mark background */
  mark?: boolean;
  /** Single-line truncate with ellipsis */
  truncate?: boolean;
  /** Multi-line clamp (number of lines) */
  lines?: 1 | 2 | 3 | 4 | 5;
  /** Tabular numbers — fixed-width digits */
  numeric?: boolean;
  /** Inline code styling */
  code?: boolean;
  /** Show copy icon on hover, copies text content on click */
  copyable?: boolean;
  className?: string;
  children?: React.ReactNode;
}

const LINES_MAP: Record<number, string> = {
  1: 'line-clamp-1',
  2: 'line-clamp-2',
  3: 'line-clamp-3',
  4: 'line-clamp-4',
  5: 'line-clamp-5',
};

const Text = React.forwardRef<HTMLElement, TextProps>(
  (
    {
      as: Tag = 'span',
      size,
      weight,
      color,
      align,
      leading,
      tracking,
      strong,
      italic,
      underline,
      strikethrough,
      gradient,
      mark,
      truncate,
      lines,
      numeric,
      code,
      copyable,
      className,
      children,
      onClick,
      ...props
    },
    ref
  ) => {
    const { copied, copy } = useCopy();
    const elRef = React.useRef<HTMLElement>(null);
    const mergedRef = (node: HTMLElement | null) => {
      (elRef as React.MutableRefObject<HTMLElement | null>).current = node;
      if (typeof ref === 'function') ref(node);
      else if (ref) (ref as React.MutableRefObject<HTMLElement | null>).current = node;
    };

    const handleClick = (e: React.MouseEvent<HTMLElement>) => {
      if (copyable && elRef.current) {
        copy(elRef.current.innerText);
      }
      onClick?.(e);
    };

    return (
      <Tag
        ref={mergedRef}
        className={cn(
          textVariants({ size, weight, color, align, leading, tracking }),
          strong       && 'font-bold',
          italic       && 'italic',
          underline    && 'underline underline-offset-2',
          strikethrough && 'line-through',
          gradient     && 'bg-gradient-to-r from-primary to-indigo-500 bg-clip-text text-transparent',
          mark         && 'bg-warning/20 text-warning-foreground rounded px-0.5',
          truncate     && 'block max-w-full truncate',
          lines        && cn('block', LINES_MAP[lines]),
          numeric      && 'tabular-nums',
          code         && 'font-mono text-[0.9em] bg-muted rounded px-1 py-0.5 border border-border/50',
          copyable     && 'cursor-pointer group/copy inline-flex items-center gap-1.5',
          className,
        )}
        onClick={handleClick}
        {...props}
      >
        {children}
        {copyable && (
          <span className="opacity-0 group-hover/copy:opacity-60 transition-opacity shrink-0">
            {copied
              ? <Check className="w-3.5 h-3.5 text-success" />
              : <Copy className="w-3.5 h-3.5" />
            }
          </span>
        )}
      </Tag>
    );
  }
);
Text.displayName = 'Text';

